#include "EmitIR.hpp"
#include <llvm/Transforms/Utils/ModuleUtils.h>

#define self (*this)

using namespace asg;

EmitIR::EmitIR(Obj::Mgr& mgr, llvm::LLVMContext& ctx, llvm::StringRef mid)
  : mMgr(mgr)
  , mMod(mid, ctx)
  , mCtx(ctx)
  , mIntTy(llvm::Type::getInt32Ty(ctx))
  , mCurIrb(std::make_unique<llvm::IRBuilder<>>(ctx))
  , mCtorTy(llvm::FunctionType::get(llvm::Type::getVoidTy(ctx), false))
{
}

llvm::Module&
EmitIR::operator()(asg::TranslationUnit* tu)
{
  for (auto&& i : tu->decls)
    self(i);
  return mMod;
}

//==============================================================================
// 类型
//==============================================================================

llvm::Type*
EmitIR::operator()(const Type* type)
{
  if (type->texp == nullptr) {
    switch (type->spec) {
      case Type::Spec::kInt:
        return llvm::Type::getInt32Ty(mCtx);
      case Type::Spec::kVoid:
        return llvm::Type::getVoidTy(mCtx);
      default:
        ABORT();
    }
  }

  Type subt;
  subt.spec = type->spec;
  subt.qual = type->qual;
  subt.texp = type->texp->sub;

  if (auto p = type->texp->dcst<PointerType>()) {
    return llvm::PointerType::get(mCtx, 0);
  }

  if (auto p = type->texp->dcst<ArrayType>()) {
    auto elemTy = self(&subt);
    if (p->len == ArrayType::kUnLen) {
      return llvm::PointerType::get(mCtx, 0);
    }
    return llvm::ArrayType::get(elemTy, p->len);
  }

  if (auto p = type->texp->dcst<FunctionType>()) {
    std::vector<llvm::Type*> pty;
    for (auto&& paramType : p->params) {
      pty.push_back(self(paramType));
    }
    return llvm::FunctionType::get(self(&subt), std::move(pty), false);
  }

  ABORT();
}

//==============================================================================
// 表达式
//==============================================================================

llvm::Value*
EmitIR::operator()(Expr* obj)
{
  if (auto p = obj->dcst<IntegerLiteral>())
    return self(p);

  if (auto p = obj->dcst<DeclRefExpr>())
    return self(p);

  if (auto p = obj->dcst<BinaryExpr>())
    return self(p);

  if (auto p = obj->dcst<UnaryExpr>())
    return self(p);

  if (auto p = obj->dcst<CallExpr>())
    return self(p);

  if (auto p = obj->dcst<ParenExpr>())
    return self(p->sub);

  ABORT();
}

llvm::Constant*
EmitIR::operator()(IntegerLiteral* obj)
{
  return llvm::ConstantInt::get(self(obj->type), obj->val);
}

llvm::Value*
EmitIR::operator()(DeclRefExpr* obj)
{
  if (auto p = obj->decl->any_as<llvm::Function>()) {
    return p;
  }
  if (auto p = obj->decl->any_as<llvm::GlobalVariable>()) {
    return mCurIrb->CreateLoad(mIntTy, p);
  }
  if (auto p = obj->decl->any_as<llvm::AllocaInst>()) {
    return mCurIrb->CreateLoad(mIntTy, p);
  }
  ABORT();
}

llvm::Value*
EmitIR::operator()(BinaryExpr* obj)
{
  auto lft = self(obj->lft);
  auto rht = self(obj->rht);

  switch (obj->op) {
    case BinaryExpr::kAdd:
      return mCurIrb->CreateAdd(lft, rht);
    case BinaryExpr::kSub:
      return mCurIrb->CreateSub(lft, rht);
    case BinaryExpr::kMul:
      return mCurIrb->CreateMul(lft, rht);
    case BinaryExpr::kDiv:
      return mCurIrb->CreateSDiv(lft, rht);
    case BinaryExpr::kMod:
      return mCurIrb->CreateSRem(lft, rht);
    case BinaryExpr::kLt:
      return mCurIrb->CreateICmpSLT(lft, rht);
    case BinaryExpr::kGt:
      return mCurIrb->CreateICmpSGT(lft, rht);
    case BinaryExpr::kLe:
      return mCurIrb->CreateICmpSLE(lft, rht);
    case BinaryExpr::kGe:
      return mCurIrb->CreateICmpSGE(lft, rht);
    case BinaryExpr::kEq:
      return mCurIrb->CreateICmpEQ(lft, rht);
    case BinaryExpr::kNe:
      return mCurIrb->CreateICmpNE(lft, rht);
    case BinaryExpr::kAnd:
      return mCurIrb->CreateAnd(lft, rht);
    case BinaryExpr::kOr:
      return mCurIrb->CreateOr(lft, rht);
    case BinaryExpr::kLAnd: {
      auto trueBB = llvm::BasicBlock::Create(mCtx, "and.true", mCurFunc);
      auto endBB = llvm::BasicBlock::Create(mCtx, "and.end", mCurFunc);
      auto cond = mCurIrb->CreateICmpNE(lft, llvm::ConstantInt::get(mIntTy, 0));
      mCurIrb->CreateCondBr(cond, trueBB, endBB);

      mCurIrb->SetInsertPoint(trueBB);
      auto rhtVal = self(obj->rht);
      auto trueBr = mCurIrb->GetInsertBlock();
      mCurIrb->CreateBr(endBB);

      mCurIrb->SetInsertPoint(endBB);
      auto phi = mCurIrb->CreatePHI(mIntTy, 2);
      phi->addIncoming(llvm::ConstantInt::get(mIntTy, 0), mCurIrb->GetInsertBlock()->getSinglePredecessor());
      phi->addIncoming(rhtVal, trueBr);
      return phi;
    }
    case BinaryExpr::kLOr: {
      auto trueBB = llvm::BasicBlock::Create(mCtx, "or.true", mCurFunc);
      auto endBB = llvm::BasicBlock::Create(mCtx, "or.end", mCurFunc);
      auto cond = mCurIrb->CreateICmpNE(lft, llvm::ConstantInt::get(mIntTy, 0));
      mCurIrb->CreateCondBr(cond, endBB, trueBB);

      mCurIrb->SetInsertPoint(trueBB);
      auto rhtVal = self(obj->rht);
      auto trueBr = mCurIrb->GetInsertBlock();
      mCurIrb->CreateBr(endBB);

      mCurIrb->SetInsertPoint(endBB);
      auto phi = mCurIrb->CreatePHI(mIntTy, 2);
      phi->addIncoming(llvm::ConstantInt::get(mIntTy, 1), mCurIrb->GetInsertBlock()->getSinglePredecessor());
      phi->addIncoming(rhtVal, trueBr);
      return phi;
    }
    case BinaryExpr::kAssign: {
      if (auto ref = obj->lft->dcst<DeclRefExpr>()) {
        if (auto glob = ref->decl->any_as<llvm::GlobalVariable>()) {
          mCurIrb->CreateStore(rht, glob);
          return rht;
        }
        if (auto alloca = ref->decl->any_as<llvm::AllocaInst>()) {
          mCurIrb->CreateStore(rht, alloca);
          return rht;
        }
      }
      ABORT();
    }
    default:
      ABORT();
  }
}

llvm::Value*
EmitIR::operator()(UnaryExpr* obj)
{
  auto sub = self(obj->sub);
  switch (obj->op) {
    case UnaryExpr::kNeg:
      return mCurIrb->CreateNeg(sub);
    case UnaryExpr::kPos:
      return sub;
    default:
      ABORT();
  }
}

llvm::Value*
EmitIR::operator()(CallExpr* obj)
{
  auto func = llvm::dyn_cast<llvm::Function>(self(obj->head));
  std::vector<llvm::Value*> args;
  for (auto&& arg : obj->args) {
    args.push_back(self(arg));
  }
  return mCurIrb->CreateCall(func, args);
}

//==============================================================================
// 语句
//==============================================================================

void
EmitIR::operator()(Stmt* obj)
{
  if (auto p = obj->dcst<CompoundStmt>())
    return self(p);

  if (auto p = obj->dcst<ReturnStmt>())
    return self(p);

  if (auto p = obj->dcst<DeclStmt>())
    return self(p);

  if (auto p = obj->dcst<ExprStmt>())
    return self(p);

  if (auto p = obj->dcst<IfStmt>())
    return self(p);

  if (auto p = obj->dcst<WhileStmt>())
    return self(p);

  if (auto p = obj->dcst<BreakStmt>())
    return self(p);

  if (auto p = obj->dcst<ContinueStmt>())
    return self(p);

  ABORT();
}

void
EmitIR::operator()(CompoundStmt* obj)
{
  for (auto&& stmt : obj->subs)
    self(stmt);
}

void
EmitIR::operator()(ReturnStmt* obj)
{
  auto& irb = *mCurIrb;

  llvm::Value* retVal;
  if (!obj->expr)
    retVal = nullptr;
  else
    retVal = self(obj->expr);

  mCurIrb->CreateRet(retVal);

  auto exitBb = llvm::BasicBlock::Create(mCtx, "return_exit", mCurFunc);
  mCurIrb->SetInsertPoint(exitBb);
}

void
EmitIR::operator()(DeclStmt* obj)
{
  for (auto&& decl : obj->decls) {
    self(decl);
  }
}

void
EmitIR::operator()(ExprStmt* obj)
{
  if (obj->expr) {
    self(obj->expr);
  }
}

void
EmitIR::operator()(IfStmt* obj)
{
  auto& irb = *mCurIrb;
  auto cond = self(obj->cond);
  auto condVal = irb.CreateICmpNE(cond, llvm::ConstantInt::get(mIntTy, 0));

  auto thenBB = llvm::BasicBlock::Create(mCtx, "if.then", mCurFunc);
  auto elseBB = obj->else_ ? llvm::BasicBlock::Create(mCtx, "if.else", mCurFunc) : nullptr;
  auto endBB = llvm::BasicBlock::Create(mCtx, "if.end", mCurFunc);

  irb.CreateCondBr(condVal, thenBB, elseBB ? elseBB : endBB);

  irb.SetInsertPoint(thenBB);
  self(obj->then);
  if (irb.GetInsertBlock()->getTerminator() == nullptr) {
    irb.CreateBr(endBB);
  }

  if (obj->else_) {
    irb.SetInsertPoint(elseBB);
    self(obj->else_);
    if (irb.GetInsertBlock()->getTerminator() == nullptr) {
      irb.CreateBr(endBB);
    }
  }

  irb.SetInsertPoint(endBB);
}

void
EmitIR::operator()(WhileStmt* obj)
{
  auto& irb = *mCurIrb;

  auto condBB = llvm::BasicBlock::Create(mCtx, "while.cond", mCurFunc);
  auto bodyBB = llvm::BasicBlock::Create(mCtx, "while.body", mCurFunc);
  auto endBB = llvm::BasicBlock::Create(mCtx, "while.end", mCurFunc);

  irb.CreateBr(condBB);
  irb.SetInsertPoint(condBB);

  auto cond = self(obj->cond);
  auto condVal = irb.CreateICmpNE(cond, llvm::ConstantInt::get(mIntTy, 0));
  irb.CreateCondBr(condVal, bodyBB, endBB);

  irb.SetInsertPoint(bodyBB);
  mWhileEndBB.push(endBB);
  mWhileCondBB.push(condBB);
  self(obj->body);
  mWhileEndBB.pop();
  mWhileCondBB.pop();

  if (irb.GetInsertBlock()->getTerminator() == nullptr) {
    irb.CreateBr(condBB);
  }

  irb.SetInsertPoint(endBB);
}

void
EmitIR::operator()(BreakStmt* obj)
{
  if (!mWhileEndBB.empty()) {
    mCurIrb->CreateBr(mWhileEndBB.top());
  } else {
    ABORT();
  }
}

void
EmitIR::operator()(ContinueStmt* obj)
{
  if (!mWhileCondBB.empty()) {
    mCurIrb->CreateBr(mWhileCondBB.top());
  } else {
    ABORT();
  }
}

//==============================================================================
// 声明
//==============================================================================

void
EmitIR::operator()(Decl* obj)
{
  if (auto p = obj->dcst<FunctionDecl>())
    return self(p);

  if (auto p = obj->dcst<VarDecl>())
    return self(p);

  ABORT();
}

void
EmitIR::operator()(VarDecl* obj)
{
  auto type = self(obj->type);

  if (mCurFunc == nullptr) {
    auto glob = new llvm::GlobalVariable(
      mMod,
      type,
      false,
      llvm::GlobalVariable::ExternalLinkage,
      nullptr,
      obj->name);

    if (obj->init) {
      auto initVal = self(obj->init);
      glob->setInitializer(llvm::dyn_cast<llvm::Constant>(initVal));
    } else {
      glob->setInitializer(llvm::ConstantInt::get(llvm::dyn_cast<llvm::IntegerType>(type), 0));
    }

    obj->any = glob;
  }
  else {
    auto alloca = mCurIrb->CreateAlloca(type, nullptr, obj->name);
    obj->any = alloca;

    if (obj->init) {
      auto initVal = self(obj->init);
      mCurIrb->CreateStore(initVal, alloca);
    }
  }
}

void
EmitIR::operator()(FunctionDecl* obj)
{
  std::vector<llvm::Type*> paramTypes;
  for (auto&& param : obj->params) {
    paramTypes.push_back(self(param->type));
  }

  auto retType = self(obj->type);
  auto funcType = llvm::FunctionType::get(retType, paramTypes, false);

  auto func = llvm::Function::Create(
    funcType, llvm::GlobalVariable::ExternalLinkage, obj->name, mMod);

  obj->any = func;

  if (obj->body == nullptr)
    return;

  auto entryBB = llvm::BasicBlock::Create(mCtx, "entry", func);
  mCurIrb->SetInsertPoint(entryBB);

  auto argIt = func->arg_begin();
  for (auto&& param : obj->params) {
    auto paramAlloca = mCurIrb->CreateAlloca(argIt->getType(), nullptr, param->name);
    param->any = paramAlloca;
    mCurIrb->CreateStore(argIt, paramAlloca);
    argIt->setName(param->name);
    ++argIt;
  }

  mCurFunc = func;
  self(obj->body);

  auto& exitIrb = *mCurIrb;
  if (exitIrb.GetInsertBlock()->getTerminator() == nullptr) {
    if (retType->isVoidTy()) {
      exitIrb.CreateRetVoid();
    } else {
      exitIrb.CreateUnreachable();
    }
  }
}
